impl Solution { pub fn next_greater_elements(black_n: Vec<i32>) -> Vec<i32> { let black_len = black_n.len(); let mut black_res = vec![-1; black_len]; let mut black_s = vec![]; for i in 0..black_len * 2 { while let Some(&idx) = black_s.last() { if black_n[i % black_len] > black_n[idx] { black_res[black_s.pop().unwrap()] = black_n[i % black_len]; } else { break; } } if i < black_len { black_s.push(i); } } black_res } }